     1|/**
     2| * IVX Owner AI Request Orchestrator.
     3| *
     4| * Single entry point for every AI execution path in the Owner chat. Replaces
     5| * scattered direct calls to assistantReplyMutation with an explicit state machine,
     6| * synchronous checkpoint recording, and guaranteed cleanup.
     7| */
     8|
     9|import { ivxAIWatchdog, type WatchdogTraceHandle } from './ivxAIWatchdog';
    10|
    11|export type AIOrchestratorState =
    12|  | 'IDLE'
    13|  | 'USER_MESSAGE_ACCEPTED'
    14|  | 'AI_TRIGGER_DECISION'
    15|  | 'AI_MUTATION_STARTED'
    16|  | 'HTTP_REQUEST_STARTED'
    17|  | 'HTTP_RESPONSE_RECEIVED'
    18|  | 'RESPONSE_PERSISTED'
    19|  | 'UI_RENDERED'
    20|  | 'SUCCESS'
    21|  | 'VALIDATION_FAILED'
    22|  | 'AUTH_FAILED'
    23|  | 'NETWORK_FAILED'
    24|  | 'PROVIDER_FAILED'
    25|  | 'TIMEOUT'
    26|  | 'CANCELLED';
    27|
    28|export interface AIOrchestratorContext {
    29|  traceId: string;
    30|  messageId: string;
    31|  conversationId: string | null;
    32|  ownerId: string | null;
    33|  mode: 'ai_only' | 'send_and_ai' | 'send_only' | 'knowledge' | 'attachment';
    34|  source: string;
    35|  startTimeMs: number;
    36|  httpRequestStarted: boolean;
    37|  httpResponseReceived: boolean;
    38|  retryCount: number;
    39|  terminal: boolean;
    40|}
    41|
    42|export interface AIOrchestratorPayload {
    43|  text: string;
    44|  traceId: string;
    45|  nonBlocking: boolean;
    46|  conversationId: string | null;
    47|  ownerId: string | null;
    48|  mode: AIOrchestratorContext['mode'];
    49|  source: string;
    50|}
    51|
    52|export interface AIOrchestratorCallbacks {
    53|  onTransition: (state: AIOrchestratorState, prev: AIOrchestratorState, ctx: AIOrchestratorContext) => void;
    54|  onExecute: (payload: AIOrchestratorPayload) => Promise<void>;
    55|  isMounted: () => boolean;
    56|  hasConversationId: () => string | null;
    57|  hasOwnerSession: () => boolean;
    58|}
    59|
    60|interface AIOrchestratorResult {
    61|  state: AIOrchestratorState;
    62|  context: AIOrchestratorContext;
    63|}
    64|
    65|export function createAIOrchestrator(callbacks: AIOrchestratorCallbacks) {
    66|  const activeRequests = new Map<string, AIOrchestratorContext>();
    67|
    68|  function transition(
    69|    ctx: AIOrchestratorContext,
    70|    next: AIOrchestratorState,
    71|    data?: Record<string, unknown>,
    72|  ): void {
    73|    const prev = ctx.terminal ? ctx.terminalState ?? 'IDLE' : (activeRequests.get(ctx.traceId)?.state as AIOrchestratorState | undefined) ?? 'IDLE';
    74|    ctx.state = next;
    75|    callbacks.onTransition(next, prev, ctx);
    76|  }
    77|
    78|  function startWatchdog(ctx: AIOrchestratorContext): void {
    79|    const trace = ivxAIWatchdog.getTrace(ctx.traceId);
    80|    if (!trace) return;
    81|    trace.pass('AI_MUTATION_STARTED', `orchestrator start mode=${ctx.mode} source=${ctx.source}`, {
    82|      messageId: ctx.messageId,
    83|      conversationId: ctx.conversationId,
    84|    });
    85|  }
    86|
    87|  function markHttpStarted(ctx: AIOrchestratorContext): void {
    88|    if (ctx.httpRequestStarted) return;
    89|    ctx.httpRequestStarted = true;
    90|    const trace = ivxAIWatchdog.getTrace(ctx.traceId);
    91|    trace?.pass('BACKEND_POST_STARTED', 'HTTP request began', { messageId: ctx.messageId });
    92|  }
    93|
    94|  function markHttpFinished(ctx: AIOrchestratorContext, status?: number): void {
    95|    ctx.httpResponseReceived = true;
    96|    const trace = ivxAIWatchdog.getTrace(ctx.traceId);
    97|    trace?.pass('BACKEND_POST_FINISHED', 'HTTP response received', { messageId: ctx.messageId, status });
    98|  }
    99|
   100|  async function execute(payload: AIOrchestratorPayload): Promise<AIOrchestratorResult> {
   101|    const ctx: AIOrchestratorContext = {
   102|      traceId: payload.traceId,
   103|      messageId: payload.messageId,
   104|      conversationId: payload.conversationId,
   105|      ownerId: payload.ownerId,
   106|      mode: payload.mode,
   107|      source: payload.source,
   108|      startTimeMs: Date.now(),
   109|      httpRequestStarted: false,
   110|      httpResponseReceived: false,
   111|      retryCount: 0,
   112|      terminal: false,
   113|    };
   114|
   115|    activeRequests.set(ctx.traceId, ctx);
   116|    transition(ctx, 'USER_MESSAGE_ACCEPTED');
   117|
   118|    try {
   119|      // Pre-flight checks (synchronous)
   120|      if (!callbacks.isMounted()) {
   121|        transition(ctx, 'VALIDATION_FAILED', { reason: 'component unmounted' });
   122|        return finalize(ctx, 'VALIDATION_FAILED');
   123|      }
   124|      if (!payload.text || payload.text.trim().length === 0) {
   125|        transition(ctx, 'VALIDATION_FAILED', { reason: 'empty text' });
   126|        return finalize(ctx, 'VALIDATION_FAILED');
   127|      }
   128|      if (payload.mode !== 'send_only' && !callbacks.hasOwnerSession()) {
   129|        transition(ctx, 'AUTH_FAILED', { reason: 'owner session missing' });
   130|        return finalize(ctx, 'AUTH_FAILED');
   131|      }
   132|      const conversationId = callbacks.hasConversationId();
   133|      if (payload.mode !== 'send_only' && !conversationId) {
   134|        transition(ctx, 'VALIDATION_FAILED', { reason: 'conversation id missing' });
   135|        return finalize(ctx, 'VALIDATION_FAILED');
   136|      }
   137|      if (conversationId) {
   138|        ctx.conversationId = conversationId;
   139|      }
   140|
   141|      transition(ctx, 'AI_TRIGGER_DECISION', { mode: payload.mode, source: payload.source });
   142|
   143|      if (payload.mode === 'send_only') {
   144|        transition(ctx, 'SUCCESS');
   145|        return finalize(ctx, 'SUCCESS');
   146|      }
   147|
   148|      // Synchronously mark AI_MUTATION_STARTED before any async work
   149|      transition(ctx, 'AI_MUTATION_STARTED');
   150|      startWatchdog(ctx);
   151|
   152|      // Execute the AI request (awaited, no fire-and-forget)
   153|      try {
   154|        markHttpStarted(ctx);
   155|        await callbacks.onExecute(payload);
   156|        markHttpFinished(ctx);
   157|      } catch (err) {
   158|        const error = err instanceof Error ? err : new Error(String(err));
   159|        if (error.name === 'AbortError' || error.message.toLowerCase().includes('abort')) {
   160|          transition(ctx, 'CANCELLED', { reason: error.message });
   161|          return finalize(ctx, 'CANCELLED');
   162|        }
   163|        if (!ctx.httpRequestStarted) {
   164|          transition(ctx, 'NETWORK_FAILED', { reason: error.message });
   165|          return finalize(ctx, 'NETWORK_FAILED');
   166|        }
   167|        if (!ctx.httpResponseReceived) {
   168|          transition(ctx, 'TIMEOUT', { reason: error.message });
   169|          return finalize(ctx, 'TIMEOUT');
   170|        }
   171|        transition(ctx, 'PROVIDER_FAILED', { reason: error.message });
   172|        return finalize(ctx, 'PROVIDER_FAILED');
   173|      }
   174|
   175|      transition(ctx, 'RESPONSE_PERSISTED');
   176|      transition(ctx, 'UI_RENDERED');
   177|      transition(ctx, 'SUCCESS');
   178|      return finalize(ctx, 'SUCCESS');
   179|    } catch (unexpected) {
   180|      const error = unexpected instanceof Error ? unexpected : new Error(String(unexpected));
   181|      transition(ctx, 'PROVIDER_FAILED', { reason: error.message });
   182|      return finalize(ctx, 'PROVIDER_FAILED');
   183|    }
   184|  }
   185|
   186|  function finalize(ctx: AIOrchestratorContext, terminal: AIOrchestratorState): AIOrchestratorResult {
   187|    ctx.terminal = true;
   188|    ctx.state = terminal;
   189|    const trace = ivxAIWatchdog.getTrace(ctx.traceId);
   190|    if (terminal === 'SUCCESS') {
   191|      trace?.complete('SUCCESS');
   192|    } else {
   193|      trace?.fail(ctx.httpRequestStarted ? 'BACKEND_POST_FINISHED' : 'AI_MUTATION_STARTED', `terminal=${terminal}`);
   194|    }
   195|    activeRequests.delete(ctx.traceId);
   196|    return { state: terminal, context: ctx };
   197|  }
   198|
   199|  function cancel(traceId: string): void {
   200|    const ctx = activeRequests.get(traceId);
   201|    if (!ctx || ctx.terminal) return;
   202|    transition(ctx, 'CANCELLED');
   203|    finalize(ctx, 'CANCELLED');
   204|  }
   205|
   206|  return {
   207|    execute,
   208|    cancel,
   209|    markHttpStarted,
   210|    markHttpFinished,
   211|    getContext: (traceId: string) => activeRequests.get(traceId),
   212|  };
   213|}
   214|
   215|export type AIOrchestrator = ReturnType<typeof createAIOrchestrator>;

