     1|/**
     2| * IVX Owner AI Watchdog.
     3| *
     4| * Produces a structured, per-message diagnostic report covering 14 checkpoints
     5| * from the user tapping Send to the assistant bubble being rendered.
     6| *
     7| * Goals:
     8| * - Eliminate silent failures: if any checkpoint fails or the trace times out
     9| *   after 10s without reaching SUCCESS, a BLOCKED report is emitted.
    10| * - Make failures observable from inside the app: subscribers (the chat UI)
    11| *   re-render a red banner showing failedCheckpoint / lastSuccessfulCheckpoint
    12| *   / fileLine / nextFix.
    13| * - Persist the last 20 reports to AsyncStorage so they survive reloads and
    14| *   can be screenshot from the in-app debug drawer.
    15| */
    16|
    17|import AsyncStorage from '@react-native-async-storage/async-storage';
    18|import {
    19|  analyzeBackendPostFailures,
    20|  type AnalyzableWatchdogReport,
    21|  type BackendPostFailureAnalysis,
    22|} from './ivxBackendPostFailureAnalyzer';
    23|
    24|export type CheckpointName =
    25|  | 'SEND_TAP'
    26|  | 'USER_ROW_INSERTED'
    27|  | 'AI_TRIGGER_DECISION'
    28|  | 'AI_MUTATION_STARTED'
    29|  | 'BACKEND_POST_STARTED'
    30|  | 'BACKEND_POST_FINISHED'
    31|  | 'ASSISTANT_TEXT_PRESENT'
    32|  | 'ASSISTANT_TRANSIENT_CREATED'
    33|  | 'MESSAGE_ARRAY_MERGED'
    34|  | 'FILTER_VISIBLE_PASSED'
    35|  | 'DEDUP_PASSED'
    36|  | 'SEARCH_PIN_FILTER_PASSED'
    37|  | 'RENDER_MESSAGE_CALLED'
    38|  | 'ASSISTANT_BUBBLE_VISIBLE';
    39|
    40|export const CHECKPOINT_ORDER: CheckpointName[] = [
    41|  'SEND_TAP',
    42|  'USER_ROW_INSERTED',
    43|  'AI_TRIGGER_DECISION',
    44|  'AI_MUTATION_STARTED',
    45|  'BACKEND_POST_STARTED',
    46|  'BACKEND_POST_FINISHED',
    47|  'ASSISTANT_TEXT_PRESENT',
    48|  'ASSISTANT_TRANSIENT_CREATED',
    49|  'MESSAGE_ARRAY_MERGED',
    50|  'FILTER_VISIBLE_PASSED',
    51|  'DEDUP_PASSED',
    52|  'SEARCH_PIN_FILTER_PASSED',
    53|  'RENDER_MESSAGE_CALLED',
    54|  'ASSISTANT_BUBBLE_VISIBLE',
    55|];
    56|
    57|/** Each checkpoint owns a file:line so failures map straight to source. */
    58|export const CHECKPOINT_OWNER: Record<CheckpointName, string> = {
    59|  SEND_TAP: 'expo/app/ivx/chat.tsx:handleSend',
    60|  USER_ROW_INSERTED: 'expo/app/ivx/chat.tsx:handleSend (setPendingOwnerMessages)',
    61|  AI_TRIGGER_DECISION: 'expo/app/ivx/chat.tsx:sendMessageMutation (auto-trigger branch)',
    62|  AI_MUTATION_STARTED: 'expo/app/ivx/chat.tsx:assistantReplyMutation.mutationFn',
    63|  BACKEND_POST_STARTED: 'expo/src/modules/ivx-owner-ai/services/ivxAIRequestService.ts:requestOwnerAI',
    64|  BACKEND_POST_FINISHED: 'expo/src/modules/ivx-owner-ai/services/ivxAIRequestService.ts:requestOwnerAI',
    65|  ASSISTANT_TEXT_PRESENT: 'expo/app/ivx/chat.tsx:assistantReplyMutation (normalizedAnswer guard)',
    66|  ASSISTANT_TRANSIENT_CREATED: 'expo/app/ivx/chat.tsx:assistantReplyMutation (setTransientAssistantMessages)',
    67|  MESSAGE_ARRAY_MERGED: 'expo/app/ivx/chat.tsx:allMessages useMemo',
    68|  FILTER_VISIBLE_PASSED: 'expo/app/ivx/chat.tsx:isInternalTranscriptMessage',
    69|  DEDUP_PASSED: 'expo/app/ivx/chat.tsx:allMessages (transient/persistent dedup)',
    70|  SEARCH_PIN_FILTER_PASSED: 'expo/app/ivx/chat.tsx:displayedMessages',
    71|  RENDER_MESSAGE_CALLED: 'expo/app/ivx/chat.tsx:renderMessage',
    72|  ASSISTANT_BUBBLE_VISIBLE: 'expo/app/ivx/chat.tsx:FlatList onViewableItemsChanged',
    73|};
    74|
    75|export const CHECKPOINT_FIX_HINT: Record<CheckpointName, string> = {
    76|  SEND_TAP: 'Send handler never fired. Check composer guards and isPending flags.',
    77|  USER_ROW_INSERTED: 'pendingOwnerMessages was not updated. Verify normalizeComposerText and setPendingOwnerMessages.',
    78|  AI_TRIGGER_DECISION: 'send_and_ai branch did not run. Check command prefix, localFirstChatMode, elevated confirmation early-return.',
    79|  AI_MUTATION_STARTED: 'assistantReplyMutation.mutate() not invoked. Check sendMessageMutation success path / swallowed rejection.',
    80|  BACKEND_POST_STARTED: 'No HTTP request issued. Verify base URL resolver and auth token retrieval.',
    81|  BACKEND_POST_FINISHED: 'Backend never responded or threw before parsing. Check network, status code, reliability wrapper timeout.',
    82|  ASSISTANT_TEXT_PRESENT: 'Backend returned empty answer. Check provider output and assertCleanOwnerAIResponseText.',
    83|  ASSISTANT_TRANSIENT_CREATED: 'setTransientAssistantMessages never ran. Check exceptions between BACKEND_POST_FINISHED and the setter.',
    84|  MESSAGE_ARRAY_MERGED: 'allMessages useMemo did not include the assistant message. Check dedup map and dependency array.',
    85|  FILTER_VISIBLE_PASSED: 'isInternalTranscriptMessage hid the assistant message. Verify senderRole is "assistant", not "system".',
    86|  DEDUP_PASSED: 'Dedup logic dropped both transient and persistent rows. Inspect bodies / ids.',
    87|  SEARCH_PIN_FILTER_PASSED: 'Active search or pin-only mode is filtering this message. Clear search or exit pin view.',
    88|  RENDER_MESSAGE_CALLED: 'FlatList never asked renderMessage for this id. Check displayedMessages and key extractor.',
    89|  ASSISTANT_BUBBLE_VISIBLE: 'Bubble rendered but never became viewable. Try scrolling or check container height.',
    90|};
    91|
    92|export type CheckpointStatus = 'pending' | 'pass' | 'fail';
    93|
    94|export interface CheckpointSnapshot {
    95|  name: CheckpointName;
    96|  status: CheckpointStatus;
    97|  expected: string;
    98|  actual: string | null;
    99|  fileLine: string;
   100|  at: string | null;
   101|  data: Record<string, unknown>;
   102|}
   103|
   104|export type FinalStatus = 'PENDING' | 'SUCCESS' | 'DEGRADED' | 'VISIBLE_ERROR' | 'SILENT_FAILURE' | 'BLOCKED';
   105|
   106|export interface WatchdogReport {
   107|  traceId: string;
   108|  conversationId: string | null;
   109|  userMessageId: string;
   110|  userText: string;
   111|  startedAt: string;
   112|  endedAt: string | null;
   113|  finalStatus: FinalStatus;
   114|  lastSuccessfulCheckpoint: CheckpointName | null;
   115|  failedCheckpoint: CheckpointName | null;
   116|  failureReason: string | null;
   117|  fileLine: string | null;
   118|  fixHint: string | null;
   119|  /** HTTP status code of the failing backend call, when known. */
   120|  statusCode: number | null;
   121|  /** Raw backend response body/preview captured at the point of failure. */
   122|  backendResponse: string | null;
   123|  /**
   124|   * Recovery metadata for a DEGRADED (recovered-via-fallback) finalization.
   125|   * Populated from the BACKEND_POST_FINISHED checkpoint data so a yellow
   126|   * DEGRADED_RECOVERY banner shows the REAL degraded route + status +
   127|   * classification instead of blank "—" fields. Null on non-degraded reports.
   128|   */
   129|  recovery: WatchdogRecoveryInfo | null;
   130|  checkpoints: CheckpointSnapshot[];
   131|  assistantTransientIds: string[];
   132|}
   133|
   134|/** Structured recovery context surfaced on a DEGRADED report. */
   135|export interface WatchdogRecoveryInfo {
   136|  recoveredViaFallback: boolean;
   137|  /** The privileged route that degraded (e.g. /api/ivx/owner-ai). */
   138|  degradedRoute: string | null;
   139|  /** The route the answer was actually recovered through. */
   140|  recoveredRoute: string | null;
   141|  /** HTTP status of the degraded privileged route, when known. */
   142|  statusCode: number | null;
   143|  /** Failure classification of the degraded route (auth/network/etc.). */
   144|  classification: string | null;
   145|  /** Human-readable reason the privileged route degraded. */
   146|  reason: string | null;
   147|}
   148|
   149|const CHECKPOINT_EXPECTED: Record<CheckpointName, string> = {
   150|  SEND_TAP: 'send handler called',
   151|  USER_ROW_INSERTED: 'user message persisted or local row added',
   152|  AI_TRIGGER_DECISION: 'Owner AI branch selected',
   153|  AI_MUTATION_STARTED: 'assistantReplyMutation.mutationFn starts',
   154|  BACKEND_POST_STARTED: 'POST /api/ivx/owner-ai sent',
   155|  BACKEND_POST_FINISHED: 'HTTP response received',
   156|  ASSISTANT_TEXT_PRESENT: 'non-empty assistant text',
   157|  ASSISTANT_TRANSIENT_CREATED: 'visible assistant transient created',
   158|  MESSAGE_ARRAY_MERGED: 'assistant message exists in allMessages before filters',
   159|  FILTER_VISIBLE_PASSED: 'assistant message not removed by system/internal filters',
   160|  DEDUP_PASSED: 'assistant message not removed by dedup',
   161|  SEARCH_PIN_FILTER_PASSED: 'assistant message not hidden by search/pin filters',
   162|  RENDER_MESSAGE_CALLED: 'renderMessage called for assistant id',
   163|  ASSISTANT_BUBBLE_VISIBLE: 'visible assistant bubble on screen',
   164|};
   165|
   166|const STORAGE_KEY = 'ivx.owner-ai.watchdog.reports.v1';
   167|const MAX_REPORTS = 20;
   168|/**
   169| * Watchdog ceiling. Audit-class prompts ("audit end to end…", senior-developer
   170| * reports, landing-page review, etc.) legitimately run many backend tool calls
   171| * and can take 60–90s server-side. A 10s ceiling produced false-positive
   172| * SILENT_FAILUREs while the real fetch was still in-flight. We now use 90s as
   173| * the default ceiling and let callers extend further for heavy audits.
   174| */
   175|const DEFAULT_TIMEOUT_MS = 90_000;
   176|const HEAVY_AUDIT_TIMEOUT_MS = 180_000;
   177|
   178|const HEAVY_AUDIT_PATTERN = /\b(audit|end[-\s]?to[-\s]?end|senior\s+developer|full\s+report|landing\s+page|inspect.*(?:project|app|backend)|deep\s+(?:scan|inspection)|complete\s+(?:report|audit))\b/i;
   179|
   180|function resolveAdaptiveTimeoutMs(userText: string): number {
   181|  if (typeof userText === 'string' && HEAVY_AUDIT_PATTERN.test(userText)) {
   182|    return HEAVY_AUDIT_TIMEOUT_MS;
   183|  }
   184|  return DEFAULT_TIMEOUT_MS;
   185|}
   186|
   187|export interface TapEvent {
   188|  at: string;
   189|  blocked: boolean;
   190|  reason: string | null;
   191|  details: Record<string, unknown>;
   192|}
   193|
   194|export interface WatchdogSnapshot {
   195|  finalized: WatchdogReport[];
   196|  active: WatchdogReport[];
   197|  lastTap: TapEvent | null;
   198|  tapCount: number;
   199|  blockedTapCount: number;
   200|}
   201|
   202|type Listener = (snapshot: WatchdogSnapshot) => void;
   203|
   204|class WatchdogStore {
   205|  private reports: WatchdogReport[] = [];
   206|  private listeners = new Set<Listener>();
   207|  private active = new Map<string, ActiveTrace>();
   208|  private byTransientId = new Map<string, string>();
   209|  private hydrated = false;
   210|  private lastTap: TapEvent | null = null;
   211|  private tapCount = 0;
   212|  private blockedTapCount = 0;
   213|  /**
   214|   * Coalesced, deferred-emit guard. Watchdog checkpoints (pass/fail/heartbeat)
   215|   * are reported from render-path code (FlatList renderMessage, message-merge
   216|   * memos). If emit() called subscriber setState synchronously, React threw
   217|   * "Cannot update a component (IVXWatchdog…) while rendering a different
   218|   * component." Emitting on a microtask moves every subscriber update OUT of
   219|   * the render phase, so the warning is impossible while still updating the UI
   220|   * on the very next tick.
   221|   */
   222|  private flushScheduled = false;
   223|
   224|  private buildSnapshot(): WatchdogSnapshot {
   225|    return {
   226|      finalized: this.reports.slice(),
   227|      active: Array.from(this.active.values()).map((t) => ({ ...t.report, checkpoints: t.report.checkpoints.map((cp) => ({ ...cp })) })),
   228|      lastTap: this.lastTap,
   229|      tapCount: this.tapCount,
   230|      blockedTapCount: this.blockedTapCount,
   231|    };
   232|  }
   233|
   234|  recordTap(at: string): void {
   235|    this.tapCount += 1;
   236|    this.lastTap = { at, blocked: false, reason: null, details: {} };
   237|    this.emit();
   238|  }
   239|
   240|  recordTapBlocked(at: string, reason: string, details: Record<string, unknown>): void {
   241|    this.tapCount += 1;
   242|    this.blockedTapCount += 1;
   243|    this.lastTap = { at, blocked: true, reason, details };
   244|    this.emit();
   245|  }
   246|
   247|  async hydrate(): Promise<void> {
   248|    if (this.hydrated) return;
   249|    this.hydrated = true;
   250|    try {
   251|      const raw = await AsyncStorage.getItem(STORAGE_KEY);
   252|      if (raw) {
   253|        const parsed = JSON.parse(raw) as WatchdogReport[];
   254|        if (Array.isArray(parsed)) {
   255|          this.reports = parsed.slice(0, MAX_REPORTS);
   256|          this.emit();
   257|        }
   258|
   259|      }
   260|    } catch (err) {
   261|      console.log('[IVXWatchdog] hydrate failed:', err instanceof Error ? err.message : 'unknown');
   262|    }
   263|  }
   264|
   265|  getReports(): WatchdogReport[] {
   266|    return this.reports;
   267|  }
   268|
   269|  getSnapshot(): WatchdogSnapshot {
   270|    return this.buildSnapshot();
   271|  }
   272|
   273|  subscribe(listener: Listener): () => void {
   274|    this.listeners.add(listener);
   275|    listener(this.buildSnapshot());
   276|    return () => {
   277|      this.listeners.delete(listener);
   278|    };
   279|  }
   280|
   281|  register(trace: ActiveTrace): void {
   282|    this.active.set(trace.report.traceId, trace);
   283|  }
   284|
   285|  bindTransient(traceId: string, transientId: string): void {
   286|    this.byTransientId.set(transientId, traceId);
   287|    const trace = this.active.get(traceId);
   288|    if (trace) {
   289|      trace.report.assistantTransientIds.push(transientId);
   290|    }
   291|  }
   292|
   293|  getActive(traceId: string): ActiveTrace | undefined {
   294|    return this.active.get(traceId);
   295|  }
