      <View style={styles.headerRow}>
        <SafeIcon icon={cfg.icon} size={16} color={cfg.color} />
        <Text style={[styles.headerText, { color: cfg.color }]}>{cfg.label}</Text>
        {dismissible ? (
          <Pressable onPress={() => setStage('idle')} style={styles.closeButton} hitSlop={8}>
